{
  "grammar": [
    {
      "pattern": "Subject + 本來 + Verb + 但 + 因為 + Reason + 所以 + 取消 / 改期",
      "structure": ["Subject", "本來", "Verb", "但", "因為", "Reason", "所以", "取消/改期"],
      "explanation_en": "Use this pattern to express that you originally planned to do something but had to cancel or reschedule due to a reason.",
      "title": "Expressing Cancellation or Rescheduling Due to Reason",
      "meaning": "Originally planned but canceled/rescheduled because of...",
      "when_to_use": ["When explaining a change in plans", "When giving a reason for canceling or rescheduling"],
      "when_not_to_use": ["When the plan is still on", "When no reason is needed"],
      "pragmatic_notes": "In Taiwan, it's polite to give a brief reason when canceling or rescheduling, even if it's vague like '臨時有事'.",
      "word_order_notes": "The reason clause comes after '因為' and before '所以'.",
      "english_contrast": "English often uses 'I was going to... but...' or 'I had to cancel because...'.",
      "korean_contrast": "Korean uses '-(으)려고 했는데... 때문에 취소/연기했어요'.",
      "negative_examples": [
        {
          "text": "我本來要取消，因為臨時有事。",
          "error": "Missing '所以' to connect reason and result."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我本來要取消，因為臨時有事。",
          "error": "Should be: 我本來要取消，但因為臨時有事，所以取消了。"
        }
      ],
      "transformation_drills": ["Change '取消' to '改期' and adjust the reason.", "Change the subject to '他' and the reason to '生病'."],
      "production_drills": ["Tell your friend why you canceled the dinner.", "Explain why you rescheduled the meeting."],
      "common_error_patterns": ["Omitting '所以'", "Using '因為' after '所以'"],
      "repair_feedback": {
        "word_order": "Put the reason after '因為' and before '所以'.",
        "politeness": "Adding '抱歉' at the beginning makes it more polite.",
        "vocabulary": "Use '臨時有事' for a vague reason."
      }
    },
    {
      "pattern": "Subject + 想 + 邀請 + Person + 但 + 對方 + 婉拒 + 因為 + Reason",
      "structure": ["Subject", "想", "邀請", "Person", "但", "對方", "婉拒", "因為", "Reason"],
      "explanation_en": "Use this pattern to describe an invitation that was politely declined, along with the reason.",
      "title": "Describing a Declined Invitation",
      "meaning": "Wanted to invite someone but they declined because...",
      "when_to_use": ["When reporting that an invitation was turned down", "When explaining why someone said no"],
      "when_not_to_use": ["When the invitation was accepted", "When you are the one declining"],
      "pragmatic_notes": "In Taiwan, '婉拒' is a polite way to say 'decline', often used in formal or semi-formal contexts.",
      "word_order_notes": "The reason comes after '因為'.",
      "english_contrast": "English uses 'I wanted to invite... but they declined because...'.",
      "korean_contrast": "Korean uses '초대하고 싶었는데 거절했어요... 때문에'.",
      "negative_examples": [
        {
          "text": "我想邀請他，但他婉拒。",
          "error": "Missing the reason for the decline."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我想邀請他，但他婉拒。",
          "error": "Should add a reason: 我想邀請他，但他婉拒，因為他臨時有事。"
        }
      ],
      "transformation_drills": ["Change '邀請' to '約' and adjust the sentence.", "Change the reason to '他太忙了'."],
      "production_drills": ["Tell your friend why your invitation was declined.", "Explain why you declined an invitation."],
      "common_error_patterns": ["Omitting the reason", "Using '拒絕' instead of '婉拒' (less polite)"],
      "repair_feedback": {
        "word_order": "Place the reason after '因為'.",
        "politeness": "Use '婉拒' instead of '拒絕' for politeness.",
        "vocabulary": "Use '臨時有事' or '太忙了' as common reasons."
      }
    },
    {
      "pattern": "Subject + 跟 + Person + 喬 + Time + 因為 + 行程 + 有 + 衝突",
      "structure": ["Subject", "跟", "Person", "喬", "Time", "因為", "行程", "有", "衝突"],
      "explanation_en": "Use this pattern to say that you are negotiating a time with someone because of a schedule conflict.",
      "title": "Negotiating Time Due to Schedule Conflict",
      "meaning": "Negotiating time with someone because of a schedule conflict",
      "when_to_use": ["When rescheduling due to a conflict", "When trying to find a common free time"],
      "when_not_to_use": ["When there is no conflict", "When the time is already fixed"],
      "pragmatic_notes": "In Taiwan, '喬時間' is a common colloquial expression for negotiating or adjusting schedules.",
      "word_order_notes": "The person comes after '跟', and the time comes after '喬'.",
      "english_contrast": "English uses 'I'm negotiating a time with... because of a schedule conflict.'",
      "korean_contrast": "Korean uses '...와 시간을 조율하고 있어요. 일정이 겹쳐서.'",
      "negative_examples": [
        {
          "text": "我跟他喬時間，因為行程衝突。",
          "error": "Missing '有' before '衝突'."
        }
      ],
      "incorrect_examples": [
        {
          "text": "我跟他喬時間，因為行程衝突。",
          "error": "Should be: 我跟他喬時間，因為行程有衝突。"
        }
      ],
      "transformation_drills": ["Change '喬' to '確認' and adjust the sentence.", "Change the conflict to '時間' instead of '行程'."],
      "production_drills": ["Tell your colleague why you need to reschedule.", "Explain to a friend that you have a conflict."],
      "common_error_patterns": ["Omitting '有' before '衝突'", "Using '安排' instead of '喬' (less colloquial)"],
      "repair_feedback": {
        "word_order": "Place '有' before '衝突'.",
        "politeness": "Using '喬' is casual; in formal settings, use '協調'.",
        "vocabulary": "Use '行程衝突' for schedule conflict."
      }
    }
  ]
}
